class Playground {
  async run(inputs) {
    const arr = inputs[0].split(',').map(x => parseInt(x.trim()));
    const n = arr.length;

    // Initialize both arrays
    this.nums.init(arr);
    this.prefix.init(new Array(n).fill(0));

    this.log('Computing Prefix Sum Array');
    this.log('prefix[i] = sum of all elements from 0 to i');
    await this.await();

    // First element
    const prefix = new Array(n).fill(0);
    prefix[0] = arr[0];
    this.nums.highlight(0, '#3b82f6');
    this.prefix.set(0, prefix[0]);
    this.prefix.highlight(0, '#10b981');
    this.log(`prefix[0] = nums[0] = ${arr[0]}`);
    await this.await();

    // Build prefix sum
    for (let i = 1; i < n; i++) {
      this.ptr.set('i', i);

      // Highlight current element in nums
      this.nums.highlight(i, '#3b82f6');
      this.log(`Processing index ${i}: nums[${i}] = ${arr[i]}`);
      await this.await();

      // Calculate prefix sum
      prefix[i] = prefix[i - 1] + arr[i];

      // Show calculation
      this.prefix.highlight(i - 1, '#f59e0b');
      this.log(`prefix[${i}] = prefix[${i-1}] + nums[${i}] = ${prefix[i-1]} + ${arr[i]} = ${prefix[i]}`);
      await this.await();

      // Update prefix array visualization
      this.prefix.set(i, prefix[i]);
      this.prefix.highlight(i, '#10b981');
      this.nums.highlight(i, '#10b981');
      this.log(`✓ Updated prefix[${i}] = ${prefix[i]}`);
      await this.await();

      // Clear for next iteration
      this.nums.clearHighlights();
      this.prefix.clearHighlights();
    }

    this.ptr.remove('i');

    // Final highlight
    for (let i = 0; i < n; i++) {
      this.nums.highlight(i, '#10b981');
      this.prefix.highlight(i, '#10b981');
    }

    this.log('✅ Prefix Sum Complete!');
    await this.await();

    // Demo: Range sum query
    if (n >= 4) {
      this.nums.clearHighlights();
      this.prefix.clearHighlights();

      this.log('📊 Demo: Range Sum Query [1, 3]');
      const l = 1, r = 3;
      await this.await();

      // Highlight range
      for (let i = l; i <= r; i++) {
        this.nums.highlight(i, '#f59e0b');
      }
      this.prefix.highlight(r, '#3b82f6');
      this.prefix.highlight(l - 1, '#ef4444');

      const rangeSum = prefix[r] - (l > 0 ? prefix[l - 1] : 0);
      this.log(`Sum[${l}..${r}] = prefix[${r}] - prefix[${l-1}] = ${prefix[r]} - ${prefix[l-1]} = ${rangeSum}`);
      await this.await();
    }

    return prefix;
  }
}
